function hasBalancedParentheses1(characters) {
    const myStack = new MyStack();
    if(characters.length === 0) return true;
    if(characters.length % 2 !== 0) return false;

    for(const ch of characters) {
        switch(ch) {
            case '{':
            case '(':
            case '<':
            case '[':
                myStack.push(ch);
                break;
            case '}':
